int main() {
    int arr[] = {10, 5, 8, 2, 9, 6, 4, 7, 3, 1};
    int size = sizeof(arr) / sizeof(arr[0]);

    int max = arr[0];
    int min = arr[0];

    // 寻找数组中的最大值和最小值
    int i;
    for (i = 1; i < size; i++) {
        if (arr[i] > max) {
            max = arr[i];
        }
        if (arr[i] < min) {
            min = arr[i];
        }
    }

    // 计算最大值和最小值的平方和
    int squareSum = (max * max) + (min * min);

    printf("The square sum of the maximum and minimum elements in the array is: %d\n", squareSum);

    return 0;
}
