#include <stdio.h>
#include <string.h>

void replaceDigitsWithAsterisk(char* str) {
    int length = strlen(str);
    for (int i = 0; i < length; i++) {
        if (str[i] >= '0' && str[i] <= '9') {
            str[i] = '*';
        }
    }
}

int main() {
    char str[] = "ab3cd1ef9g";
    printf("Before replacement: %s\n", str);

    replaceDigitsWithAsterisk(str);

    printf("After replacement: %s\n", str);

    return 0;
}
```

输出结果:
```
Before replacement: ab3cd1ef9g
After replacement: ab*cd*ef*g
```

