#include <stdio.h>

int countAboveAverage(int arr[], int n) {
    int sum = 0;

    for (int i = 0; i < n; i++) {
        sum += arr[i];
    }

    double average = (double)sum / n;
    int count = 0;

    for (int i = 0; i < n; i++) {
        if (arr[i] > average) {
            count++;
        }
    }

    return count;
}

int main() {
